@typeparam TItem
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:100%;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            <div class="spinner-border text-secondary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-e5666223e13545ff863a4e71beebea63/infinite-scroll.js");
        }

        // (Re-)observe the sentinel whenever it may have been re-added to the DOM.
        if (HasMore && _module is not null)
        {
            await _module.InvokeVoidAsync("observe", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnIntersecting()
    {
        if (_isLoading || !HasMore) return;
        _isLoading = true;

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("disconnect"); } catch { }
            try { await _module.DisposeAsync(); } catch { }
        }
        _dotNetRef?.Dispose();
    }
}

let observer = null;

export function observe(sentinel, dotNetRef) {
    disconnect();

    observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync("OnIntersecting");
            }
        }
    }, { rootMargin: "200px" });

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

